// Solution
#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
int longest_increasing_subsequence(vector<int>& arr) {
  int n = arr.size();
  vector<int> dp(n, 1);
  for (int i = 1; i < n; i++) {
    for (int j = 0; j < i; j++) {
      if (arr[i] > arr[j]) {
        dp[i] = max(dp[i], dp[j] + 1);
      }
    }
  }
  int max_len = 0;
  for (int i = 0; i < n; i++) {
    max_len = max(max_len, dp[i]);
  }
  return max_len;
}
};

int main() {
  cin.tie(0);
  ios_base::sync_with_stdio(0);
  int t;
  cin >> t;
  while (t--) {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) {
      cin >> arr[i];
    }
    Solution s;
    cout << s.longest_increasing_subsequence(arr) << endl;
  }
  return 0;
}

