  int t = scanner.nextInt();
  while (t-- > 0) {
    int n = scanner.nextInt();
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
      arr[i] = scanner.nextInt();
    }
    Solution s = new Solution();
    System.out.println(s.longest_increasing_subsequence(arr));
  }
}
public int longest_increasing_subsequence(int[] arr) {
  int n = arr.length;
  int[] dp = new int[n];
  for (int i = 0; i < n; i++) {
    dp[i] = 1;
  }
  for (int i = 1; i < n; i++) {
    for (int j = 0; j < i; j++) {
      if (arr[i] > arr[j]) {
        dp[i] = Math.max(dp[i], dp[j] + 1);
      }
    }
  }
  int max_len = 0;
  for (int i = 0; i < n; i++) {
    max_len = Math.max(max_len, dp[i]);
  }
  return max_len;
}

