// Solution
import sys
from collections import defaultdict

class Solution:
  def longest_increasing_subsequence(self, arr: list[int]) -> int:
    n = len(arr)
    dp = [1] * n
    for i in range(1, n):
      for j in range(i):
        if arr[i] > arr[j]:
          dp[i] = max(dp[i], dp[j] + 1)
    max_len = 0
    for i in range(n):
      max_len = max(max_len, dp[i])
    return max_len

if __name__ == '__main__':
  t = int(input())
  for _ in range(t):
    n = int(input())
    arr = list(map(int, input().split()))
    s = Solution()
    print(s.longest_increasing_subsequence(arr))

